Module 1: Storage &amp; Database Set up the DynamoDB single-table for generic data storage and an S3 bucket for storing application assets.
Create lib/storage-stack.ts:
import * as cdk from &#39;aws-cdk-lib&#39;; import * as dynamodb from &#39;aws-cdk-lib/aws-dynamodb&#39;; import * as s3 from &#39;aws-cdk-lib/aws-s3&#39;; import { Construct } from &#39;constructs&#39;; export class StorageStack extends cdk.Stack { public readonly table: dynamodb.Table; public readonly assetBucket: s3.Bucket; constructor(scope: Construct, id: string, props?: cdk.StackProps) { super(scope, id, props); // Initialize DynamoDB Single Table for generic entity metadata this.table = new dynamodb.Table(this, &#39;AppSingleTable&#39;, { partitionKey: { name: &#39;PK&#39;, type: dynamodb.AttributeType.STRING }, sortKey: { name: &#39;SK&#39;, type: dynamodb.AttributeType.STRING }, billingMode: dynamodb.BillingMode.PAY_PER_REQUEST, // On-Demand pricing pointInTimeRecovery: true, // Enables automated backups removalPolicy: cdk.RemovalPolicy.DESTROY, // Dev environment cleanup }); // Create private S3 Bucket for application assets this.assetBucket = new s3.Bucket(this, &#39;AssetStorageBucket&#39;, { encryption: s3.BucketEncryption.S3_MANAGED, blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL, // Secure private bucket removalPolicy: cdk.RemovalPolicy.DESTROY, autoDeleteObjects: true, }); } }

Module 2: Compute &amp; API Gateway Wire a backend Lambda function and expose it through API Gateway. Since we are using a fully serverless architecture, the Lambda function runs in the default AWS-managed network and communicates directly with DynamoDB.
Create lib/api-stack.ts:
import * as cdk from &#39;aws-cdk-lib&#39;; import * as lambda from &#39;aws-cdk-lib/aws-lambda&#39;; import * as apigateway from &#39;aws-cdk-lib/aws-apigateway&#39;; import * as cognito from &#39;aws-cdk-lib/aws-cognito&#39;; import * as dynamodb from &#39;aws-cdk-lib/aws-dynamodb&#39;; import { Construct } from &#39;constructs&#39;; interface ApiStackProps extends cdk.StackProps { table: dynamodb.Table; userPool: cognito.IUserPool; } export class ApiStack extends cdk.Stack { constructor(scope: Construct, id: string, props: ApiStackProps) { super(scope, id, props); const authorizer = new apigateway.CognitoUserPoolsAuthorizer(this, &#39;AppApiAuthorizer&#39;, { cognitoUserPools: [props.userPool], authorizerName: &#39;AppAuthorizer&#39;, }); const dataLambda = new lambda.Function(this, &#39;DataServiceLambda&#39;, { runtime: lambda.Runtime.NODEJS_18_X, handler: &#39;index.handler&#39;, code: lambda.Code.fromInline(` const { DynamoDBClient } = require(&#34;@aws-sdk/client-dynamodb&#34;); const { DynamoDBDocumentClient, ScanCommand } = require(&#34;@aws-sdk/lib-dynamodb&#34;); const client = new DynamoDBClient({}); const docClient = DynamoDBDocumentClient.from(client); exports.handler = async (event) =&gt; { const tableName = process.env.TABLE_NAME; try { const data = await docClient.send(new ScanCommand({ TableName: tableName, FilterExpression: &#34;begins_with(PK, :pk)&#34;, ExpressionAttributeValues: { &#34;:pk&#34;: &#34;ITEM#&#34; } })); return { statusCode: 200, headers: { &#34;Content-Type&#34;: &#34;application/json&#34;, &#34;Access-Control-Allow-Origin&#34;: &#34;*&#34; }, body: JSON.stringify(data.Items || []) }; } catch (err) { return { statusCode: 500, body: JSON.stringify({ error: err.message }) }; } }; `), environment: { TABLE_NAME: props.table.tableName, }, }); props.table.grantReadWriteData(dataLambda); const api = new apigateway.RestApi(this, &#39;AppRestApi&#39;, { restApiName: &#39;Application Backend API&#39;, defaultCorsPreflightOptions: { allowOrigins: apigateway.Cors.ALL_ORIGINS, allowMethods: apigateway.Cors.ALL_METHODS, }, }); const itemsResource = api.root.addResource(&#39;items&#39;); itemsResource.addMethod(&#39;GET&#39;, new apigateway.LambdaIntegration(dataLambda)); itemsResource.addMethod(&#39;POST&#39;, new apigateway.LambdaIntegration(dataLambda), { authorizer: authorizer, authorizationType: apigateway.AuthorizationType.COGNITO, }); } }

Module 3: Security &amp; Permissions Set up Cognito User Pool for login and create fine-grained IAM policies following the principle of Least Privilege.
Create lib/security-stack.ts:
import * as cdk from &#39;aws-cdk-lib&#39;; import * as cognito from &#39;aws-cdk-lib/aws-cognito&#39;; import * as iam from &#39;aws-cdk-lib/aws-iam&#39;; import { Construct } from &#39;constructs&#39;; export class SecurityStack extends cdk.Stack { public readonly userPool: cognito.UserPool; public readonly userPoolClient: cognito.UserPoolClient; constructor(scope: Construct, id: string, props?: cdk.StackProps) { super(scope, id, props); this.userPool = new cognito.UserPool(this, &#39;AppUserPool&#39;, { userPoolName: &#39;app-user-pool&#39;, selfSignUpEnabled: true, signInAliases: { email: true }, autoVerify: { email: true }, passwordPolicy: { minLength: 8, requireLowercase: true, requireUppercase: true, requireDigits: true, requireSymbols: true, }, removalPolicy: cdk.RemovalPolicy.DESTROY, }); this.userPoolClient = new cognito.UserPoolClient(this, &#39;AppUserPoolClient&#39;, { userPool: this.userPool, generateSecret: false, }); // Custom role for notification system (Least Privilege) const notificationRole = new iam.Role(this, &#39;NotificationPublishRole&#39;, { assumedBy: new iam.ServicePrincipal(&#39;lambda.amazonaws.com&#39;), description: &#39;Role for sending notifications with minimal permissions&#39;, }); notificationRole.addToPolicy(new iam.PolicyStatement({ actions: [&#39;sns:Publish&#39;], resources: [&#39;*&#39;], effect: iam.Effect.ALLOW, })); } }

Cleanup &amp; Advanced Topics 1. Cleanup Resources To prevent charges, always destroy the resources after you finish testing:
cdk destroy --all 2. Infrastructure Testing (Jest) Verify stack resources properties automatically. Create test/infra.test.ts:
import * as cdk from &#39;aws-cdk-lib&#39;; import { Template } from &#39;aws-cdk-lib/assertions&#39;; import * as Storage from &#39;../lib/storage-stack&#39;; test(&#39;DynamoDB table configuration is correct&#39;, () =&gt; { const app = new cdk.App(); const stack = new Storage.StorageStack(app, &#39;TestStack&#39;); const template = Template.fromStack(stack); template.hasResourceProperties(&#39;AWS::DynamoDB::Table&#39;, { BillingMode: &#39;PAY_PER_REQUEST&#39;, }); });
